{
    solver          PCG;
    preconditioner  DIC;
    tolerance       1e-05;
    relTol          0.1;
}

epsilon
{
    solver          PCG;
    preconditioner  DIC;
    tolerance       1e-05;
    relTol          0.1;
}

nut
